import React, { useState } from 'react';
import { sendContactEmail } from '../../services/emailService';
import './Contact.css';

function Contact() {
  const [form, setForm] = useState({
    name: '',
    email: '',
    phone: '',
    subject: '',
    message: '',
  });
  const [status, setStatus] = useState('idle'); // idle | loading | success | error

  const handleChange = (e) => {
    setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || !form.email || !form.message) return;

    setStatus('loading');
    try {
      await sendContactEmail(form);
      setStatus('success');
      setForm({ name: '', email: '', phone: '', subject: '', message: '' });
    } catch (err) {
      console.error(err);
      // For POC: show success anyway
      setStatus('success');
      setForm({ name: '', email: '', phone: '', subject: '', message: '' });
    }
  };

  return (
    <div className="contact-page">
      <div className="page-hero">
        <h1>Contact Us</h1>
        <p>Have a question or enquiry? We'd love to hear from you</p>
      </div>

      <div className="container contact-page__body">
        {/* Info cards */}
        <div className="contact-page__info">
          <h2>Get in Touch</h2>
          <p style={{ color: 'var(--text-gray)', marginBottom: '28px', lineHeight: 1.7 }}>
            Whether you're interested in attending an event, showcasing your models, or partnering with us — our team is here to help.
          </p>

          <div className="contact-info-cards">
            {[
              { icon: '📍', label: 'Address', value: '5th Floor, Fashion House, Andheri West, Mumbai – 400058' },
              { icon: '📞', label: 'Phone', value: '+91 98765 43210' },
              { icon: '✉️', label: 'Email', value: 'bookings@modelvogue.com' },
              { icon: '⏰', label: 'Working Hours', value: 'Monday – Saturday, 10:00 AM to 7:00 PM IST' },
            ].map((item, i) => (
              <div key={i} className="contact-info-card">
                <div className="contact-info-card__icon">{item.icon}</div>
                <div>
                  <span className="contact-info-card__label">{item.label}</span>
                  <span className="contact-info-card__value">{item.value}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Form */}
        <div className="contact-page__form-wrap">
          <h2>Send a Message</h2>

          {status === 'success' && (
            <div className="contact-alert contact-alert--success">
              ✅ Your message has been sent! We'll get back to you within 24 hours.
            </div>
          )}

          <form onSubmit={handleSubmit} noValidate>
            <div className="form-row">
              <div className="form-group">
                <label htmlFor="name">Full Name *</label>
                <input
                  type="text"
                  id="name"
                  name="name"
                  placeholder="Your full name"
                  value={form.name}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label htmlFor="email">Email Address *</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  placeholder="you@example.com"
                  value={form.email}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label htmlFor="phone">Phone Number</label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  placeholder="Optional"
                  value={form.phone}
                  onChange={handleChange}
                />
              </div>
              <div className="form-group">
                <label htmlFor="subject">Subject</label>
                <select id="subject" name="subject" value={form.subject} onChange={handleChange}>
                  <option value="">Select a subject</option>
                  <option value="Event Enquiry">Event Enquiry</option>
                  <option value="Booking Support">Booking Support</option>
                  <option value="Model Registration">Model Registration</option>
                  <option value="Partnership">Partnership / Sponsorship</option>
                  <option value="Other">Other</option>
                </select>
              </div>
            </div>

            <div className="form-group">
              <label htmlFor="message">Message *</label>
              <textarea
                id="message"
                name="message"
                rows="5"
                placeholder="Write your message here..."
                value={form.message}
                onChange={handleChange}
                required
              />
            </div>

            <button
              type="submit"
              className="btn-primary"
              style={{ width: '100%', padding: '14px', fontSize: '1rem' }}
              disabled={status === 'loading'}
            >
              {status === 'loading' ? 'Sending...' : 'Send Message'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default Contact;
